/* ── WEATHER (Open-Meteo — free, no API key) ── */
const WMO={0:'clear sky',1:'mainly clear',2:'partly cloudy',3:'overcast',45:'foggy',48:'foggy',51:'light drizzle',53:'drizzle',55:'heavy drizzle',61:'light rain',63:'rain',65:'heavy rain',71:'light snow',73:'snow',75:'heavy snow',80:'rain showers',81:'rain showers',82:'heavy showers',95:'thunderstorm',96:'thunderstorm',99:'thunderstorm'};
const getWeather=async(city='Rochdale')=>{
  try{
    const geo=await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(city)}&count=1`);
    const gd=await geo.json();
    if(!gd.results?.length)return null;
    const{latitude,longitude,name,country_code}=gd.results[0];
    const wx=await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,weathercode,windspeed_10m&temperature_unit=celsius`);
    const wd=await wx.json();
    const{temperature_2m,weathercode,windspeed_10m}=wd.current;
    const desc=WMO[weathercode]||'unknown conditions';
    return{temp:Math.round(temperature_2m),desc,wind:Math.round(windspeed_10m),city:name,country:country_code?.toUpperCase()};
  }catch{return null;}
};

